update td_plan_change_history
    set pass_flag        = #{passFlag, jdbcType= BIT},
        update_time = getdate(),
        update_by = #{updateBy, jdbcType = BIGINT}
        where parent_id = #{parentId, jdbcType = BIGINT}
        and id = (
            select max(temp.id) from td_plan_change_history temp where temp.parent_id = #{parentId, jdbcType = BIGINT}
        )
